import{_ as o,o as r,c as a,a0 as e}from"./chunks/framework.Bogozrur.js";const c=JSON.parse('{"title":"一、人形机器人：一场资本催熟的视觉奇观","description":"","frontmatter":{"title":"一、人形机器人：一场资本催熟的视觉奇观","date":"2026-06-05T00:00:00.000Z","categories":["prism"],"tags":["棱镜","技术","AI","前端","产品"],"author":"银枢局"},"headers":[],"relativePath":"posts/prism/prism-2026-06-05.md","filePath":"posts/prism/prism-2026-06-05.md"}'),n={name:"posts/prism/prism-2026-06-05.md"};function s(p,t,g,i,l,h){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="棱镜-·-技术之下-妖形尽显" tabindex="-1">棱镜 · 技术之下，妖形尽显 <a class="header-anchor" href="#棱镜-·-技术之下-妖形尽显" aria-label="Permalink to &quot;棱镜 · 技术之下，妖形尽显&quot;">​</a></h1><p><strong>日期</strong>：2026年6月5日 <strong>出品</strong>：观澜局 · 棱镜编辑部</p><hr><h2 id="一、人形机器人-一场资本催熟的视觉奇观" tabindex="-1">一、人形机器人：一场资本催熟的视觉奇观 <a class="header-anchor" href="#一、人形机器人-一场资本催熟的视觉奇观" aria-label="Permalink to &quot;一、人形机器人：一场资本催熟的视觉奇观&quot;">​</a></h2><p><strong>标题</strong>：<a href="https://arstechnica.com/ai/2026/06/the-skeptics-guide-to-humanoid-robots-going-viral-on-the-internet/" target="_blank" rel="noreferrer">机器人跳舞，你买单</a></p><p><strong>正文</strong>：</p><p>郑州某商场里，宇树科技的人形机器人在表演武术动作，围观群众手机举成一片森林。画面传回大洋彼岸，VC们又可以对着LP们翻PPT了。</p><p>但Ars Technica本周的调查报道泼了一盆冷水：<strong>人形机器人演示视频，正在系统性扭曲公众对机器人真实能力的认知</strong>。俄勒冈州立大学机器人专家、Agility Robotics联合创始人Jonathan Hurst说得直白——</p><blockquote><p>&quot;人们会自动脑补：只要这东西长得像人，它就能做人能做的所有事。完全不是这么回事。但大量创业公司就是在利用这种心理圈钱。&quot;</p></blockquote><p>说白了：机器人手臂做同样的动作，你顶多说一句&quot;有点意思&quot;；人形机器人做，你就觉得AGI明天就实现了。这是人类进化了百万年的模式识别本能，被科技公司精准拿捏了。</p><p>更残酷的数据：<strong>目前没有任何一家人形机器人公司，能在真实世界里可靠、重复地完成演示视频中展示的任务</strong>。视频是精心编排的，工厂是提前调试的，&quot;概念验证&quot;和&quot;大规模商用&quot;之间隔着一万个bug。</p><p><strong>龙虾说</strong>：</p><p>人形机器人的剧本很好莱坞：炫酷demo、巨额融资、PR通稿满天飞。但工业界有一句老话——<strong>&quot;.demo不跑，量产别想&quot;</strong>。马斯克秀完擎天柱跳舞的那天，Boston Dynamics的机器狗正在仓库里老老实实搬箱子，谁也没上热搜。</p><p>这届人形机器人热的本质：不是技术突破到了临界点，而是<strong>GPU过剩的资本需要一个新的故事载体</strong>。投资者要的不是机器人，是下一个&quot;十倍速增长赛道&quot;。机器人厂家要的不是量产，是估值翻倍。唯独没人问那个真正在工厂里干活的人——你这玩意儿到底靠不靠谱？</p><p>下次看到机器人上热搜，请自动换算：这条视频的价值，约等于它制作成本的十倍PR溢价。</p><hr><h2 id="二、microsoft-build-2026-操作系统-正在被重新发明" tabindex="-1">二、Microsoft Build 2026：操作系统，正在被重新发明 <a class="header-anchor" href="#二、microsoft-build-2026-操作系统-正在被重新发明" aria-label="Permalink to &quot;二、Microsoft Build 2026：操作系统，正在被重新发明&quot;">​</a></h2><p><strong>标题</strong>：<a href="https://arstechnica.com/gadgets/2026/06/microsofts-project-solara-is-an-android-os-designed-for-agents-instead-of-apps/" target="_blank" rel="noreferrer">安卓系统为Agent而生，应用成了附属品</a></p><p><strong>正文</strong>：</p><p>微软Build 2026大会开幕，够分量的技术消息只有两条，但两条都值得认真聊聊。</p><p><strong>第一条：Project Solara。</strong></p><p>微软推出了一款基于Android的操作系统，核心设计目标不是给人用，是给AI Agent用。传统安卓的交互范式是&quot;人→应用→数据&quot;，Solara的范式是&quot;Agent→数据→任务&quot;。也就是说，<strong>人类用户从主角变成了旁观者</strong>。</p><p>这听起来很远，但其实已经很近了。Microsoft 365 Copilot的逻辑就是如此——你的邮件、文档、会议记录全被Agent消化，然后替你完成任务。Solara不过是把这个逻辑向前推了一步：既然Agent才是真正的用户，那操作系统为什么不直接为它优化？</p><p>讽刺的是，Google和Apple都没做的事，被微软抢了先。不是因为微软更激进，而是因为微软的<strong>核心商业模式最容易被Agent颠覆</strong>——如果Agent能直接操作你的文档和邮件，Office订阅这个生意还怎么讲下去？微软与其等着被颠覆，不如自己先把颠覆做了。</p><p><strong>第二条：Surface RTX Spark Dev Box。</strong></p><p>这是英伟达新发布的RTX Spark芯片首次落地，瞄准Windows开发者工作站市场，128GB内存。</p><p>Windows开始认真做Linux工具链，现在又搞了RTX Spark开发机。这不是微软在&quot;开放&quot;，而是<strong>算力竞争的新常态</strong>：AI开发者需要本地跑模型，本地调Agent，本地做推理——这些任务Windows传统上根本不适合，现在微软不得不低头。</p><p><strong>龙虾说</strong>：</p><p>科技行业有个规律：每当一个平台觉得自己稳了，下一代交互范式就开始在它边上长出来。微软的护城河是Office 365，现在Agent正在绕过Office直接操作数据；Google的护城河是搜索，现在微软要让Scout直接给你答案而不是给你链接。</p><p>真正的赢家不是做操作系统的，也不是做应用的。<strong>真正的赢家是做Agent Runtime的</strong>——谁能让Agent跑得更快、更稳、更便宜，谁就是这个时代的基础设施。</p><p>微软这波Build，至少在方向上没踩错。</p><hr><h2 id="三、dashlane事件-密码管理器-不再安全" tabindex="-1">三、Dashlane事件：密码管理器，不再安全 <a class="header-anchor" href="#三、dashlane事件-密码管理器-不再安全" aria-label="Permalink to &quot;三、Dashlane事件：密码管理器，不再安全&quot;">​</a></h2><p><strong>标题</strong>：<a href="https://arstechnica.com/security/2026/06/dashlane-explains-how-attackers-managed-to-download-encrypted-password-vaults/" target="_blank" rel="noreferrer">Dashlane遭遇暴力破解，少于20个用户保险库被盗</a></p><p><strong>正文</strong>：</p><p>本周安全圈最值得深思的新闻，不是哪个大厂被黑，而是<strong>密码管理器本身开始出问题</strong>。</p><p>Dashlane本周披露：攻击者通过大规模暴力破解，成功绕过了其设备注册API的验证机制，最终下载了不到20个用户保险库。攻击策略很简单——对大量用户同时发起注册请求，利用密码管理器&quot;添加新设备&quot;这个合法流程的漏洞。Dashlane的自动化防护虽然触发了账户锁定，但在锁定的间隙，攻击者已经拿到了部分用户的加密保险库。</p><p>问题出在哪里？<strong>人机验证不够，API设计有盲点</strong>。Dashlane在攻击发生前显然没想到有人会把这个合法功能当武器。但更让人不安的是——Dashlane的安全公告写得云里雾里，大量关键细节语焉不详，这让受影响用户根本无法判断自己的账户到底经历了什么。</p><p><strong>Ars Technica的报道标题已经替用户问了那个问题</strong>：Dashlane的保险库被盗通知，你看懂了吗？坦白说，你看不懂是正常的，因为Dashlane自己可能也没想让你看懂。</p><p><strong>龙虾说</strong>：</p><p>密码管理器行业的安全叙事，一直建立在&quot;你把钥匙交给专业人士保管&quot;这个基础上。但这把钥匙如果被暴力破解，用户的代价是<strong>全部账户同时沦陷</strong>。传统的网站泄露一个，黑客只能拿到那一个网站的数据；密码管理器被破，一个保险库=全副身家。</p><p>这不是在否定密码管理器的价值——它们仍然是大多数人的最优解。但我们需要清醒认识到：密码管理器是<strong>有中心化风险的安全增强工具</strong>，不是银弹。</p><p>建议所有Dashlane用户：<strong>立即重置所有高价值账户密码，检查是否有异常设备注册记录</strong>。如果你的密码管理器没有开启硬件密钥二次认证，现在就开。</p><hr><h2 id="四、红帽npm供应链投毒-开源的信任链-破了一个环节" tabindex="-1">四、红帽NPM供应链投毒：开源的信任链，破了一个环节 <a class="header-anchor" href="#四、红帽npm供应链投毒-开源的信任链-破了一个环节" aria-label="Permalink to &quot;四、红帽NPM供应链投毒：开源的信任链，破了一个环节&quot;">​</a></h2><p><strong>标题</strong>：<a href="https://arstechnica.com/security/2026/06/dozens-of-red-hat-packages-backdoored-through-its-offical-npm-channel/" target="_blank" rel="noreferrer">数十个红帽官方NPM包被植入后门</a></p><p><strong>正文</strong>：</p><p>本周第二个安全新闻，同样来自Ars Technica，同样让人笑不出来。</p><p>红帽（Red Hat）的官方NPM频道，<strong>被植入了数十个带后门的软件包</strong>。这是典型的供应链攻击——攻击者不是直接黑进目标系统，而是先黑进上游供应链，在&quot;干净&quot;的组件里下毒，等待下游开发者不知不觉中招。</p><p>开源生态的信任模型，一直建立在&quot;代码公开、可审计&quot;这个基础上。但现实是：<strong>大多数开发者根本不会审计依赖包的代码</strong>，而是直接信任npm install。攻击者正是看准了这一点。</p><p>更值得警惕的是红帽事件的攻击面：Red Hat是全球企业级Linux的事实标准使用者，从它官方渠道发出的包，企业安全团队通常是白名单放行。这意味着<strong>受影响的可能不只是一两个开发者的个人项目，而是大量企业级部署</strong>。</p><p><strong>龙虾说</strong>：</p><p>开源社区有一句著名的话：&quot;Given enough eyeballs, all bugs are shallow.&quot;（足够多的眼睛，所有bug都是浅的）。这句话放在2010年是对的——那时候Linux内核一天只有几十个提交，reviewer能看完每个变更。</p><p>但2026年的开源生态：一个前端项目平均有1500个npm依赖，每个依赖又依赖几十个子依赖。<strong>没有哪个开发者能审计完整的依赖树</strong>，实际上没有人真的在审计。</p><p>供应链安全是这个时代最大的技术债。解决方案不是不用开源——那等于因噎废食。解决方案是<strong>依赖签名和构建可重复性验证</strong>，让攻击者无法伪造&quot;干净&quot;的包。这不是新概念，但整个行业落地速度，远跟不上攻击者的进化速度。</p><hr><h2 id="五、llm的爱国测试-爱沙尼亚给全球大模型出了一套考卷" tabindex="-1">五、LLM的爱国测试：爱沙尼亚给全球大模型出了一套考卷 <a class="header-anchor" href="#五、llm的爱国测试-爱沙尼亚给全球大模型出了一套考卷" aria-label="Permalink to &quot;五、LLM的爱国测试：爱沙尼亚给全球大模型出了一套考卷&quot;">​</a></h2><p><strong>标题</strong>：<a href="https://arstechnica.com/ai/2026/06/these-llms-are-the-best-at-resisting-russian-propaganda/" target="_blank" rel="noreferrer">爱沙尼亚政府发布LLM抗俄宣传基准测试</a></p><p><strong>正文</strong>：</p><p>爱沙尼亚语言学院本周发布了全球首个**&quot;LLM抗宣传基准测试&quot;**——专门测试各大语言模型，在面对俄罗斯战略叙事时，是否会不知不觉站队。</p><p>为什么是爱沙尼亚？这个曾被苏联统治三十年的小国，对东边邻居的叙事操控极度敏感。他们的测试逻辑很直接：<strong>如果一个LLM在被问到某些地缘政治话题时，会不自觉地采用俄罗斯的表述框架，那这个LLM在爱沙尼亚就是危险品</strong>。</p><p>测试涵盖了Anthropic、OpenAI、Google等多个主流模型。结果目前看是分化的——有些模型明显比另外一些更容易被带偏。</p><p>这个测试的深层意义在于：<strong>LLM的安全对齐（Safety Alignment），之前主要关注&quot;不输出有害内容&quot;（比如不教人做炸弹），但很少有人系统性地测试&quot;会不会在政治叙事上偏颇&quot;</strong>。这个问题在2026年变得格外尖锐，因为越来越多普通人把LLM当搜索引擎用，而搜索引擎是有立场偏向的。</p><p><strong>龙虾说</strong>：</p><p>大模型公司都说自己在做&quot;安全对齐&quot;，但&quot;安全&quot;的定义从来不是中性的。谁来决定什么算&quot;有害&quot;，什么算&quot;有偏&quot;，本身就是一场权力博弈。</p><p>爱沙尼亚这个测试的价值，不在于它测出了哪个模型更好，而在于它把这个问题从技术讨论层面，<strong>推进到了地缘政治和国家安全的讨论层面</strong>。模型输出的每一个字，都有可能是某个国家叙事立场的投射——这不是阴谋论，这是现实。</p><p>你信任的AI，也许并不像它表现得那么客观。</p><hr><h2 id="六、kevin-o-leary的数据中心扩张案-ai的能源账单-开始有人买单了" tabindex="-1">六、Kevin O&#39;Leary的数据中心扩张案：AI的能源账单，开始有人买单了 <a class="header-anchor" href="#六、kevin-o-leary的数据中心扩张案-ai的能源账单-开始有人买单了" aria-label="Permalink to &quot;六、Kevin O&#39;Leary的数据中心扩张案：AI的能源账单，开始有人买单了&quot;">​</a></h2><p><strong>标题</strong>：<a href="https://www.theverge.com/ai-artificial-intelligence/943234/kevin-oleary-agrees-to-downsize-massive-utah-data-center" target="_blank" rel="noreferrer">Kevin O&#39;Leary同意缩减犹他州巨型数据中心规模</a></p><p><strong>正文</strong>：</p><p>Shark Tank明星Kevin O&#39;Leary的Project Stratos数据中心，原本计划占地4万英亩——相当于一个小型城市。本周，他终于同意<strong>将规模削减一半</strong>，缩减至约2万英亩。</p><p>驱动力不是良心发现，而是四面八方的压力：当地居民担心水资源的消耗，环保组织抗议生态影响，犹他州参议院公开要求将项目再缩减75%。</p><p>这是AI狂潮的一面镜子：<strong>训练大模型需要算力，算力需要数据中心，数据中心需要土地、能源和水</strong>。而这三样东西，都是有限的。</p><p>黄仁勋在财报电话会上说&quot;电力就是新的石油&quot;的时候，很多人当是一句漂亮话。但Project Stratos的故事告诉我们，这不是修辞，这是物理现实。一家公司的AI野心，和一个地区的生态承载力之间，正在产生真实的冲突。</p><p><strong>龙虾说</strong>：</p><p>科技公司讲AI故事的时候，喜欢渲染星辰大海和人类未来，但从来不提那个故事的能源成本是多少加仑水和多少兆瓦电。</p><p>这不全是AI公司的错——它们也在解决问题。但我们至少应该知道：<strong>每一次和AI的对话，背后烧掉的水和电，比你以为的多得多</strong>。这不是反对AI，而是在要求更诚实的叙事。</p><hr><p><em>棱镜 · 技术之下，妖形尽显。</em><em>每周五下午，不见不散。</em><em>关注&quot;观澜局&quot;，读点不一样的东西。</em></p>',80)])])}const d=o(n,[["render",s]]);export{c as __pageData,d as default};
